export declare const CUSTOMER_STATEMENT_HTML =
  '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <title>Customer Statement {{document.number}}</title>\n  <style>\n    /* Statement-specific overrides */\n    .statement-details {\n      display: flex;\n      justify-content: space-between;\n      align-items: flex-start;\n      margin-bottom: 20px;\n    }\n    .statement-details .left {\n      flex: 1;\n    }\n    .statement-details .right {\n      flex: 0 0 auto;\n    }\n    .statement-period {\n      margin-bottom: 16px;\n      padding: 8px 12px;\n      background: #f0f0f0;\n      border-radius: 4px;\n      font-size: 11px;\n      color: #555;\n      text-align: center;\n    }\n    .transaction-table {\n      width: 100%;\n      border-collapse: collapse;\n      margin-bottom: 16px;\n    }\n    .transaction-table thead th {\n      background: #f0f0f0;\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #555;\n      padding: 8px 6px;\n      border-bottom: 2px solid #ccc;\n      text-align: left;\n    }\n    .transaction-table thead th.text-right {\n      text-align: right;\n    }\n    .transaction-table tbody td {\n      padding: 6px;\n      border-bottom: 1px solid #e5e5e5;\n      font-size: 11px;\n      vertical-align: top;\n    }\n    .transaction-table tbody td.text-right {\n      text-align: right;\n      font-variant-numeric: tabular-nums;\n    }\n    .transaction-table tbody tr:nth-child(even) {\n      background: #f9f9f9;\n    }\n    .transaction-table .opening-balance td,\n    .transaction-table .closing-balance td {\n      font-weight: 700;\n      border-top: 2px solid #333;\n      padding-top: 8px;\n    }\n    .transaction-table .closing-balance td {\n      font-size: 12px;\n      color: #111;\n    }\n    .overdue-notice {\n      margin-bottom: 16px;\n      padding: 10px 12px;\n      border: 1px solid #e0c050;\n      background: #fefce8;\n      font-size: 11px;\n      font-weight: 600;\n      color: #92400e;\n      text-align: center;\n    }\n  </style>\n</head>\n<body>\n  <div class="page">\n\n    \n<div class="header">\n  <div class="header-left">\n    {{#if branding.showLogo}}\n    {{#if company.logoUrl}}\n    <div class="logo-section">\n      <img src="{{company.logoUrl}}" alt="{{company.name}} logo" />\n    </div>\n    {{/if}}\n    {{/if}}\n    <div class="company-name">{{company.name}}</div>\n    {{#if company.legalName}}\n    <div class="company-legal-name">{{company.legalName}}</div>\n    {{/if}}\n  </div>\n  <div class="header-right">\n    <div class="company-details">\n      <p style="white-space:pre-line">{{company.address}}</p>\n      {{#if company.phone}}<p>Tel: {{company.phone}}</p>{{/if}}\n      {{#if company.email}}<p>{{company.email}}</p>{{/if}}\n      {{#if company.website}}<p>{{company.website}}</p>{{/if}}\n      {{#if branding.showVatNumber}}\n      {{#if company.vatNumber}}<p class="vat-number">VAT: {{company.vatNumber}}</p>{{/if}}\n      {{/if}}\n      {{#if branding.showCompanyReg}}\n      {{#if company.companyNumber}}<p class="company-reg">Reg: {{company.companyNumber}}</p>{{/if}}\n      {{/if}}\n    </div>\n  </div>\n</div>\n\n    <div class="document-title">Customer Statement</div>\n\n    <div class="statement-period">\n      Statement period: {{formatDate document.date}} to {{formatDate document.dueDate}}\n    </div>\n\n    <div class="statement-details">\n      <div class="left">\n        <div class="address-block">\n          <div class="label">To</div>\n          <div class="name">{{counterparty.name}}</div>\n          <div class="address">{{counterparty.address}}</div>\n        </div>\n      </div>\n      <div class="right">\n        <div class="document-details">\n          <table>\n            <tr><th>Statement No.</th><td>{{document.number}}</td></tr>\n            <tr><th>Date</th><td>{{formatDate document.date}}</td></tr>\n            {{#if metadata.paymentTerms}}\n            <tr><th>Payment Terms</th><td>{{metadata.paymentTerms}}</td></tr>\n            {{/if}}\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <table class="transaction-table">\n      <thead>\n        <tr>\n          <th style="width:80px">Date</th>\n          <th style="width:90px">Reference</th>\n          <th style="width:80px">Type</th>\n          <th>Description</th>\n          <th class="text-right" style="width:100px">Debit</th>\n          <th class="text-right" style="width:100px">Credit</th>\n          <th class="text-right" style="width:100px">Balance</th>\n        </tr>\n      </thead>\n      <tbody>\n        <tr class="opening-balance">\n          <td></td>\n          <td></td>\n          <td></td>\n          <td>Opening Balance</td>\n          <td class="text-right"></td>\n          <td class="text-right"></td>\n          <td class="text-right">{{formatCurrency totals.subtotal metadata.currencyCode}}</td>\n        </tr>\n        {{#each lines}}\n        <tr class="line-item-row">\n          <td>{{formatDate this.date}}</td>\n          <td>{{this.itemCode}}</td>\n          <td>{{this.transactionType}}</td>\n          <td>{{this.description}}</td>\n          {{#if (gt this.lineTotal 0)}}\n          <td class="text-right">{{formatCurrency this.lineTotal ../metadata.currencyCode}}</td>\n          <td class="text-right">&mdash;</td>\n          {{else}}\n          <td class="text-right">&mdash;</td>\n          <td class="text-right">{{formatCurrency this.lineTotal ../metadata.currencyCode}}</td>\n          {{/if}}\n          <td class="text-right">{{formatCurrency this.runningBalance ../metadata.currencyCode}}</td>\n        </tr>\n        {{/each}}\n        <tr class="closing-balance">\n          <td colspan="4">Closing Balance</td>\n          <td class="text-right"></td>\n          <td class="text-right"></td>\n          <td class="text-right">{{formatCurrency totals.amountDue metadata.currencyCode}}</td>\n        </tr>\n      </tbody>\n    </table>\n\n    <div class="summary-block">\n      <table class="aging-table">\n        <thead>\n          <tr>\n            <th>Aging</th>\n            <th>Current</th>\n            <th>30 Days</th>\n            <th>60 Days</th>\n            <th>90+ Days</th>\n            <th>Total</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr>\n            <td>Amount</td>\n            <td>{{formatCurrency metadata.agingCurrent metadata.currencyCode}}</td>\n            <td>{{formatCurrency metadata.aging30 metadata.currencyCode}}</td>\n            <td>{{formatCurrency metadata.aging60 metadata.currencyCode}}</td>\n            <td>{{formatCurrency metadata.aging90Plus metadata.currencyCode}}</td>\n            <td>{{formatCurrency totals.amountDue metadata.currencyCode}}</td>\n          </tr>\n        </tbody>\n      </table>\n    </div>\n\n    <div class="overdue-notice">\n      Please remit payment for any overdue amounts at your earliest convenience.\n    </div>\n\n    \n{{#if branding.showBankDetails}}\n<div class="bank-details">\n  <div class="section-title">Bank Details</div>\n  <table>\n    {{#if company.bankName}}\n    <tr><td>Bank</td><td>{{company.bankName}}</td></tr>\n    {{/if}}\n    {{#if company.bankSortCode}}\n    <tr><td>Sort Code</td><td>{{company.bankSortCode}}</td></tr>\n    {{/if}}\n    {{#if company.bankAccountNumber}}\n    <tr><td>Account No.</td><td>{{company.bankAccountNumber}}</td></tr>\n    {{/if}}\n  </table>\n</div>\n{{/if}}\n\n    {{#if document.notes}}\n    <div class="notes-section">\n      <div class="section-title">Notes</div>\n      {{document.notes}}\n    </div>\n    {{/if}}\n\n    \n<div class="page-footer">\n  {{company.name}} &mdash; Generated by Nexa ERP\n  <div class="page-numbers">Page <span class="pageNumber"></span> of <span class="totalPages"></span></div>\n</div>\n\n  </div>\n</body>\n</html>';
